arguments.new_str:
using System.ClientModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using OpenAI;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the AI:ApiKey configuration value or OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddSingleton<ResearchTools>();

builder.Services.AddChatClient(sp =>
    new OpenAIChatClient(
        new OpenAIClient(new ApiKeyCredential(apiKey))
            .GetChatClient(modelId)));

builder.Logging.SetMinimumLevel(LogLevel.Warning);

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();
var logger = host.Services.GetRequiredService<ILoggerFactory>().CreateLogger("ResearchAgent");

var tools = new List<AITool>
{
    AIFunctionFactory.Create(researchTools.SearchWebAsync),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    name: "Researcher",
    description: "A research agent that searches the web and summarizes findings.",
    instructions: """
        You are a research agent. Your goal is to thoroughly research the given topic
        by searching the web for relevant information, saving key findings as notes,
        then producing a final summary.

        Follow this process:
        1. Break the topic into 2-3 specific search queries.
        2. Search the web for each query.
        3. Save important findings as notes (include the source URL).
        4. After gathering enough information, retrieve all notes and write a
           comprehensive summary with source citations.
        """,
    tools: tools);

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }

    logger.LogDebug("Agent step: Role={Role}, ContentLength={Length}",
        update.Role, update.Text?.Length ?? 0);
}

Console.WriteLine();
Console.WriteLine($"\n--- Research complete. {researchTools.NoteCount} note(s) saved. ---");

