 using System.ComponentModel;
 using System.Net;
 using System.Text;
 using System.Text.Json;
 using System.Text.RegularExpressions;
 using Microsoft.Extensions.AI;

 namespace ResearchAgent;

 public sealed partial class ResearchTools
 {
     private readonly List<string> _notes = [];
     private readonly HttpClient _httpClient = new();

     public int NoteCount => _notes.Count;

     [Description("Searches the web for the given query and returns a list of result snippets with URLs.")]
     public async Task<string> SearchWebAsync(
         [Description("The search query to look up on the web.")] string query,
         CancellationToken cancellationToken = default)
     {
         // Uses the DuckDuckGo HTML endpoint (no API key required).
         var encoded = WebUtility.UrlEncode(query);
         var url = $"https://html.duckduckgo.com/html/?q={encoded}";

         var request = new HttpRequestMessage(HttpMethod.Get, url);
         request.Headers.UserAgent.ParseAdd(
             "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

         try
         {
             var response = await _httpClient.SendAsync(request, cancellationToken);
             response.EnsureSuccessStatusCode();
             var html = await response.Content.ReadAsStringAsync(cancellationToken);

             var results = ParseSearchResults(html);
             if (results.Count == 0)
             {
                 return $"No results found for \"{query}\".";
             }

             var sb = new StringBuilder();
             sb.AppendLine($"Search results for \"{query}\":");
             foreach (var (title, snippet, link) in results.Take(5))
             {
                 sb.AppendLine($"- **{title}**");
                 sb.AppendLine($"  {snippet}");
                 sb.AppendLine($"  Source: {link}");
             }

             return sb.ToString();
         }
         catch (HttpRequestException ex)
         {
             return $"Search failed: {ex.Message}";
         }
     }

     [Description("Saves a research note for later reference. Use this to record key findings from search results.")]
     public string SaveNote(
         [Description("The content of the note to save, including source attribution.")] string note)
     {
         _notes.Add(note);
         return $"Note #{_notes.Count} saved.";
     }

     [Description("Retrieves all previously saved research notes.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
         {
             return "No notes have been saved yet.";
         }

         var sb = new StringBuilder();
         sb.AppendLine($"All saved notes ({_notes.Count}):");
         for (var i = 0; i < _notes.Count; i++)
         {
             sb.AppendLine($"\n--- Note #{i + 1} ---");
             sb.AppendLine(_notes[i]);
         }

         return sb.ToString();
     }

     private static List<(string Title, string Snippet, string Url)> ParseSearchResults(string html)
     {
         var results = new List<(string, string, string)>();

         var linkMatches = ResultLinkRegex().Matches(html);
         var snippetMatches = SnippetRegex().Matches(html);

         for (var i = 0; i < linkMatches.Count && i < snippetMatches.Count; i++)
         {
             var rawUrl = WebUtility.HtmlDecode(linkMatches[i].Groups[1].Value);
             var title = StripHtml(linkMatches[i].Groups[2].Value);
             var snippet = StripHtml(snippetMatches[i].Groups[1].Value);

             // DuckDuckGo wraps URLs in a redirect; extract the real target.
             var actualUrl = ExtractRedirectUrl(rawUrl) ?? rawUrl;
             if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(snippet))
